// Pronounce service worker — AUTO-GENERATED by tools/build-site.sh. Do not edit
// by hand; edit the emitter in build-site.sh instead.
const CACHE_NAME = 'pronounce-e26845a6e6';
// Vercel serves clean URLs (/browse, not /browse.html) — precaching and matching
// the .html form meant every extensionless page missed the cache entirely and
// hard-failed offline.
const SHELL = ['/', '/browse', '/style.css', '/script.js', '/manifest.webmanifest', '/og.png'];
// Extensionless HTML pages the site actually serves. Anything not listed here
// and without a known asset extension falls through to network-first.
const PAGES = ['/browse', '/faq', '/quiz', '/receipts', '/hall-of-shame', '/scoreboard', '/about', '/collection', '/compare', '/daily'];

self.addEventListener('install', (e) => {
  e.waitUntil(caches.open(CACHE_NAME).then((c) => c.addAll(SHELL)).then(() => self.skipWaiting()));
});

self.addEventListener('activate', (e) => {
  e.waitUntil(
    caches.keys()
      .then((keys) => Promise.all(keys.filter((k) => k !== CACHE_NAME).map((k) => caches.delete(k))))
      .then(() => self.clients.claim())
  );
});

// Immutable per URL (audio clips, OG images) — cache-first is cheap and safe;
// new words get new URLs so there is nothing stale to serve.
function cacheFirst(req) {
  return caches.match(req).then((cached) => cached || fetch(req).then((res) => {
    if (res && res.status === 200) { const copy = res.clone(); caches.open(CACHE_NAME).then((c) => c.put(req, copy)); }
    return res;
  }));
}

// HTML / CSS / JS / word pages — stale-while-revalidate: serve cache instantly
// for speed + offline, but refresh it in the background so a fix reaches the
// visitor on their NEXT view (and a new deploy changes CACHE_NAME outright).
function staleWhileRevalidate(req) {
  return caches.open(CACHE_NAME).then((cache) => cache.match(req).then((cached) => {
    const network = fetch(req).then((res) => { if (res && res.status === 200) cache.put(req, res.clone()); return res; }).catch(() => cached);
    return cached || network;
  }));
}

self.addEventListener('fetch', (e) => {
  if (e.request.method !== 'GET') return;
  const url = new URL(e.request.url);
  if (url.origin !== self.location.origin) return;            // leave fonts / unpkg / analytics alone
  if (url.pathname.startsWith('/api/') || url.pathname.startsWith('/_vercel/')) return; // always fresh
  if (url.pathname.startsWith('/audio/') || url.pathname.startsWith('/og/')) { e.respondWith(cacheFirst(e.request)); return; }
  const p = url.pathname;
  if (
    SHELL.includes(p) ||
    PAGES.includes(p) ||
    PAGES.some((page) => p.startsWith(page + '/')) ||   // /collection/x, /compare/x, /daily/2026-07-12
    p.startsWith('/word/') ||
    p.startsWith('/zh/') ||
    p.startsWith('/embed/') ||
    p.endsWith('.html') ||
    p.endsWith('.css') ||
    p.endsWith('.js')
  ) { e.respondWith(staleWhileRevalidate(e.request)); return; }
  e.respondWith(fetch(e.request).catch(() => caches.match(e.request)));
});
